// Receive products from scraper
const products = $input.all();
const vendorId = products[0]?.json?.vendor_id;
const vendorTier = products[0]?.json?.vendor_tier || products[0]?.json?.tier_used;
const markettimeSKUs = $workflow.staticData.markettime_skus || [];

// Add metadata to each product including Phase 6 fields
return products.map(product => {
  const productData = product.json;

  // Extract image URLs from various possible sources
  let imageUrls = [];
  if (productData.images && Array.isArray(productData.images)) {
    imageUrls = productData.images.map(img => typeof img === 'string' ? img : img.src || img.url);
  } else if (productData.image_urls && Array.isArray(productData.image_urls)) {
    imageUrls = productData.image_urls;
  } else if (productData.image_url) {
    imageUrls = [productData.image_url];
  }

  // Extract video URLs from various possible sources
  let videoUrls = [];
  if (productData.videos && Array.isArray(productData.videos)) {
    videoUrls = productData.videos.map(vid => typeof vid === 'string' ? vid : vid.src || vid.url);
  } else if (productData.video_urls && Array.isArray(productData.video_urls)) {
    videoUrls = productData.video_urls;
  } else if (productData.video_url) {
    videoUrls = [productData.video_url];
  }

  return {
    json: {
      ...productData,
      // Phase 6 new fields
      image_urls: imageUrls.length > 0 ? JSON.stringify(imageUrls) : null,
      video_urls: videoUrls.length > 0 ? JSON.stringify(videoUrls) : null,
      vendor_id: vendorId || productData.vendor_id || null,
      source_tier: vendorTier || productData.source_tier || null,
      // Existing metadata
      is_new_markettime_item: markettimeSKUs.includes(productData.sku || productData.SKU),
      upsert_timestamp: new Date().toISOString()
    }
  };
});

// Check if incoming data is newer than existing data
const incomingProduct = $input.first().json;
const existingProduct = $node['Check if SKU Exists'].json;

const incomingDate = new Date(incomingProduct.last_updated || incomingProduct.upsert_timestamp);
const existingDate = new Date(existingProduct.last_updated);

const shouldUpdate = incomingDate > existingDate;

return [{
  json: {
    ...incomingProduct,
    should_update: shouldUpdate,
    existing_date: existingDate.toISOString(),
    incoming_date: incomingDate.toISOString()
  }
}];

// Tag the result with action taken
const item = $input.first().json;
return [{
  json: {
    ...item,
    action: 'inserted',
    timestamp: new Date().toISOString()
  }
}];

// Tag the result with action taken
const item = $input.first().json;
return [{
  json: {
    ...item,
    action: 'updated',
    timestamp: new Date().toISOString()
  }
}];

// Tag the result with action taken
const item = $input.first().json;
return [{
  json: {
    ...item,
    action: 'skipped',
    reason: 'data_not_newer',
    timestamp: new Date().toISOString()
  }
}];

// Aggregate upsert statistics
const allResults = $input.all();

const stats = {
  total_processed: allResults.length,
  products_added: allResults.filter(r => r.json.action === 'inserted').length,
  products_updated: allResults.filter(r => r.json.action === 'updated').length,
  products_skipped: allResults.filter(r => r.json.action === 'skipped').length,
  new_markettime_items: allResults.filter(r => r.json.is_new_markettime_item).length,
  vendor_id: allResults[0]?.json?.vendor_id,
  timestamp: new Date().toISOString()
};

return [{ json: stats }];
